  "transient_error_count" int NOT NULL DEFAULT 0,
  "created_at" timestamp,
  "updated_at" timestamp
);

CREATE TABLE "conversation_state" (
  "usuario_id" bigint PRIMARY KEY NOT NULL,
  "mode" varchar(30) NOT NULL DEFAULT 'active_chat',
  "awaiting_field_code" varchar(50),
  "awaiting_question_code" varchar(10),
  "last_provider_message_id" varchar(255),
  "last_turn_at" timestamp,
  "last_form_prompt_at" timestamp,
  "turns_since_last_prompt" int NOT NULL DEFAULT 0,
  "closure_score" int,
  "reply_resolved_something" boolean NOT NULL DEFAULT false,
  "profile_completion_pct" int NOT NULL DEFAULT 0,
  "usability_completion_pct" int NOT NULL DEFAULT 0,
  "last_openai_response_id" varchar(255),
  "version" int NOT NULL DEFAULT 1,
  "onboarding_status" varchar(20) NOT NULL DEFAULT 'not_started',
  "onboarding_step" varchar(50),
  "onboarding_last_invited_at" timestamp,
  "onboarding_next_eligible_at" timestamp,
  "onboarding_skip_count" int NOT NULL DEFAULT 0,
  "onboarding_updated_at" timestamp,
  "meaningful_interactions_count" int NOT NULL DEFAULT 0,
  "updated_at" timestamp
);

CREATE TABLE "profile_extractions" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
