COMMENT ON TABLE "usuarios" IS 'TABLA: usuarios

QUÉ ES:
Tabla maestra central de identidad del usuario dentro del sistema.

PARA QUÉ SIRVE:
- Unificar perfil nutricional, conversación, memoria y colas.
- Evitar duplicar usuarios por cada mensaje recibido.
- Tener un ancla estable para toda la operación.

QUÉ DEBE IR AQUÍ:
- Solo identidad técnica y mínima del usuario.
- No debe guardar enfermedades, dietas, alergias ni historial conversacional detallado.

QUÉ NO DEBE IR AQUÍ:
- Datos nutricionales
- Resúmenes clínicos
- Estado de conversación
- Mensajes o documentos
';

COMMENT ON COLUMN "usuarios"."id" IS 'Clave primaria interna del usuario. Todas las tablas de perfil, conversación y colas se anclan a este ID.';

COMMENT ON COLUMN "usuarios"."whatsapp_jid" IS 'Identificador completo del usuario en WhatsApp. Ejemplo: 51999999999@s.whatsapp.net. Sirve para integrar con el proveedor de mensajería.';

COMMENT ON COLUMN "usuarios"."numero_whatsapp" IS 'Número telefónico limpio del usuario, normalmente sin espacios ni símbolos. Sirve para búsquedas y para el envío de mensajes.';

COMMENT ON COLUMN "usuarios"."creado_en" IS 'Fecha en la que el usuario fue creado por primera vez en el sistema.';

COMMENT ON COLUMN "usuarios"."actualizado_en" IS 'Última vez que se actualizó algún dato de esta fila del usuario.';

COMMENT ON TABLE "incoming_messages" IS 'TABLA: incoming_messages

QUÉ ES:
Inbox operacional de mensajes entrantes.

PARA QUÉ SIRVE:
- Recibir mensajes del proveedor de mensajería.
- Evitar procesamiento duplicado.
- Permitir reintentos y trazabilidad.
- Separar recepción del procesamiento.

QUÉ DEBE IR AQUÍ:
- El mensaje recibido como evento técnico.
- El payload bruto del webhook.
- Estado de procesamiento.

QUÉ NO DEBE IR AQUÍ:
- Respuestas del bot
- Resumen conversacional
- Datos clínicos ya estructurados
';

COMMENT ON COLUMN "incoming_messages"."id" IS 'Clave primaria interna del mensaje recibido.';

COMMENT ON COLUMN "incoming_messages"."provider_message_id" IS 'ID único del mensaje entregado por el proveedor de WhatsApp o el gateway. Se usa para deduplicación e idempotencia.';

COMMENT ON COLUMN "incoming_messages"."usuario_id" IS 'Usuario asociado al mensaje si ya pudo resolverse. Puede venir nulo en etapas muy tempranas si aún no se identificó al usuario.';

COMMENT ON COLUMN "incoming_messages"."webhook_payload" IS 'Payload bruto completo del webhook recibido. Debe guardarse tal cual para auditoría, reprocesamiento o depuración.';

COMMENT ON COLUMN "incoming_messages"."status" IS 'Estado operativo del procesamiento del mensaje: pending, processing, done, failed.';

COMMENT ON COLUMN "incoming_messages"."locked_at" IS 'Momento en el que un worker tomó este mensaje para procesarlo. Sirve para control de concurrencia y reintentos.';

COMMENT ON COLUMN "incoming_messages"."error_detail" IS 'Último error registrado al procesar el mensaje. Solo debe usarse para diagnóstico técnico.';

COMMENT ON COLUMN "incoming_messages"."retry_count" IS 'Número de reintentos ejecutados sobre este mensaje.';

COMMENT ON COLUMN "incoming_messages"."conflict_count" IS 'Número de conflictos de concurrencia detectados al procesar el mensaje.';

COMMENT ON COLUMN "incoming_messages"."transient_error_count" IS 'Número de errores temporales o recuperables, por ejemplo fallos de red o tiempo de espera.';

COMMENT ON COLUMN "incoming_messages"."created_at" IS 'Momento en que el mensaje entró al inbox del sistema.';

COMMENT ON COLUMN "incoming_messages"."updated_at" IS 'Última actualización técnica de esta fila.';

COMMENT ON TABLE "conversation_state" IS 'TABLA: conversation_state

QUÉ ES:
Estado conversacional actual del usuario.

PARA QUÉ SIRVE:
- Saber qué está esperando el bot.
- Controlar onboarding y encuestas.
- Mantener continuidad entre mensajes.
- Evitar que el sistema pregunte cosas fuera de contexto.

QUÉ DEBE IR AQUÍ:
- Estado actual y operativo.
- No historial completo.
- No contenido clínico definitivo.

QUÉ NO DEBE IR AQUÍ:
- Mensajes completos
- Enfermedades confirmadas
- Dietas registradas como dato final
';

COMMENT ON COLUMN "conversation_state"."usuario_id" IS 'Clave primaria y foránea al usuario. Hay una sola fila vigente por usuario para representar su estado actual de conversación.';

COMMENT ON COLUMN "conversation_state"."mode" IS 'Modo operativo actual del diálogo. Ejemplo: active_chat o collecting_usability.';

COMMENT ON COLUMN "conversation_state"."awaiting_field_code" IS 'Código del campo de perfil o formulario que el bot está esperando actualmente. Ejemplo: edad, objetivo, distrito.';

COMMENT ON COLUMN "conversation_state"."awaiting_question_code" IS 'Código corto de la pregunta puntual que se espera en el flujo de usabilidad.';

COMMENT ON COLUMN "conversation_state"."last_provider_message_id" IS 'ID del último mensaje entrante relevante para este estado conversacional.';

COMMENT ON COLUMN "conversation_state"."last_turn_at" IS 'Fecha y hora del último turno efectivo del usuario o del sistema.';

COMMENT ON COLUMN "conversation_state"."last_form_prompt_at" IS 'Última vez que se pidió explícitamente una respuesta de formulario o encuesta.';

COMMENT ON COLUMN "conversation_state"."turns_since_last_prompt" IS 'Cantidad de turnos transcurridos desde la última pregunta de formulario. Sirve para no insistir demasiado.';

COMMENT ON COLUMN "conversation_state"."closure_score" IS 'Puntaje interno que estima intención de cierre o despedida. Puede servir para decidir si pedir datos o no.';

COMMENT ON COLUMN "conversation_state"."reply_resolved_something" IS 'Indica si la última respuesta del bot resolvió algo útil antes de intentar capturar más datos.';

COMMENT ON COLUMN "conversation_state"."profile_completion_pct" IS 'Porcentaje de avance estimado del perfil nutricional del usuario.';

COMMENT ON COLUMN "conversation_state"."usability_completion_pct" IS 'Porcentaje de avance estimado de la evaluación de usabilidad.';

COMMENT ON COLUMN "conversation_state"."last_openai_response_id" IS 'ID del último response o cadena conversacional usada con el proveedor de IA, si aplica.';

COMMENT ON COLUMN "conversation_state"."version" IS 'Versión interna para control de concurrencia optimista.';

COMMENT ON COLUMN "conversation_state"."onboarding_status" IS 'Estado general del onboarding: not_started, invited, in_progress, completed, skipped, paused.';

COMMENT ON COLUMN "conversation_state"."onboarding_step" IS 'Paso concreto del onboarding en el que está el usuario.';

COMMENT ON COLUMN "conversation_state"."onboarding_last_invited_at" IS 'Última vez que el sistema invitó al usuario a completar onboarding.';

COMMENT ON COLUMN "conversation_state"."onboarding_next_eligible_at" IS 'Próximo momento permitido para volver a invitar al usuario.';

COMMENT ON COLUMN "conversation_state"."onboarding_skip_count" IS 'Número de veces que el usuario ha omitido o rechazado el onboarding.';

COMMENT ON COLUMN "conversation_state"."onboarding_updated_at" IS 'Última vez que cambió algo relacionado al onboarding.';

COMMENT ON COLUMN "conversation_state"."meaningful_interactions_count" IS 'Contador de interacciones útiles para disparar encuestas, seguimiento o milestones.';

COMMENT ON COLUMN "conversation_state"."updated_at" IS 'Última actualización global de este estado conversacional.';

COMMENT ON TABLE "profile_extractions" IS 'TABLA: profile_extractions

QUÉ ES:
Registro de inferencias tentativas extraídas desde el chat.

PARA QUÉ SIRVE:
- No contaminar el perfil final con datos dudosos.
- Permitir validación posterior.
- Trazar de dónde salió cada inferencia.

QUÉ DEBE IR AQUÍ:
- Detecciones intermedias.
- Posibles campos de perfil.
- Señales que luego podrían confirmarse.

QUÉ NO DEBE IR AQUÍ:
- El dato definitivo del perfil si ya fue confirmado.
- Prescripciones dietéticas oficiales.
';

COMMENT ON COLUMN "profile_extractions"."id" IS 'Clave primaria interna de una extracción de perfil.';

COMMENT ON COLUMN "profile_extractions"."usuario_id" IS 'Usuario al que pertenece esta inferencia o extracción.';

COMMENT ON COLUMN "profile_extractions"."field_code" IS 'Nombre técnico del campo detectado. Ejemplo: edad, enfermedad, restriccion, objetivo, distrito.';

COMMENT ON COLUMN "profile_extractions"."raw_value" IS 'Texto exacto detectado en la conversación antes de normalizarlo.';

COMMENT ON COLUMN "profile_extractions"."normalized_value" IS 'Versión normalizada del raw_value, útil para matching semántico o fuzzy.';

COMMENT ON COLUMN "profile_extractions"."confidence" IS 'Nivel de confianza interno de la extracción, entre 0.00 y 1.00.';

COMMENT ON COLUMN "profile_extractions"."evidence_text" IS 'Fragmento textual o evidencia del mensaje que justifica la extracción.';

COMMENT ON COLUMN "profile_extractions"."status" IS 'Estado de la extracción: tentative, confirmed o rejected.';

COMMENT ON COLUMN "profile_extractions"."resolved_entity_type" IS 'Tipo de entidad maestra a la que se resolvió la extracción, si ya existe resolución.';

COMMENT ON COLUMN "profile_extractions"."resolved_entity_code" IS 'Código canónico de la entidad resuelta en el maestro correspondiente.';

COMMENT ON COLUMN "profile_extractions"."resolution_strategy" IS 'Estrategia usada para resolver la extracción: EXACT, TRGM, VECTOR, HYBRID, LLM.';

COMMENT ON COLUMN "profile_extractions"."semantic_cache_hit" IS 'Marca si la resolución vino desde cache semántico en lugar de recalcularse.';

COMMENT ON COLUMN "profile_extractions"."extracted_at" IS 'Momento en que esta extracción fue generada.';

COMMENT ON TABLE "extraction_jobs" IS 'TABLA: extraction_jobs

QUÉ ES:
Cola de trabajos para extracción semántica o estructurada del perfil.

PARA QUÉ SIRVE:
- Desacoplar el análisis del flujo de respuesta.
- Procesar texto fuera del camino crítico.
- Permitir reintentos y concurrencia controlada.

QUÉ DEBE IR AQUÍ:
- Trabajo pendiente de extracción.
- Texto fuente.
- Estado técnico del job.

QUÉ NO DEBE IR AQUÍ:
- Resultado final confirmado.
';

COMMENT ON COLUMN "extraction_jobs"."id" IS 'Clave primaria interna del job de extracción.';

COMMENT ON COLUMN "extraction_jobs"."usuario_id" IS 'Usuario cuyo texto será procesado por el pipeline de extracción.';

COMMENT ON COLUMN "extraction_jobs"."raw_text" IS 'Texto completo o fragmento que debe ser analizado para extraer información estructurada.';

COMMENT ON COLUMN "extraction_jobs"."status" IS 'Estado del job: pending, processing, done o failed.';

COMMENT ON COLUMN "extraction_jobs"."retry_count" IS 'Número de reintentos del job.';

COMMENT ON COLUMN "extraction_jobs"."locked_at" IS 'Momento en que un worker tomó este job para procesarlo.';

COMMENT ON COLUMN "extraction_jobs"."created_at" IS 'Fecha de creación del job.';

COMMENT ON COLUMN "extraction_jobs"."updated_at" IS 'Última actualización del job.';

COMMENT ON TABLE "outgoing_messages" IS 'TABLA: outgoing_messages

QUÉ ES:
Outbox de mensajes que el sistema debe enviar.

PARA QUÉ SIRVE:
- Controlar idempotencia.
- Permitir reintentos de salida.
- Separar generación de contenido del envío real.
- Trazar fallos y entregas.

QUÉ DEBE IR AQUÍ:
- Mensajes listos o pendientes de salida.
- Estado técnico de despacho.

QUÉ NO DEBE IR AQUÍ:
- El historial clínico del usuario.
- La lógica de nutrición como tal.
';

COMMENT ON COLUMN "outgoing_messages"."id" IS 'Clave primaria interna del mensaje saliente.';

COMMENT ON COLUMN "outgoing_messages"."idempotency_key" IS 'Clave única para evitar enviar dos veces el mismo mensaje por errores o reintentos.';

COMMENT ON COLUMN "outgoing_messages"."usuario_id" IS 'Usuario destinatario del mensaje.';

COMMENT ON COLUMN "outgoing_messages"."phone" IS 'Número final de destino usado para el envío.';

COMMENT ON COLUMN "outgoing_messages"."content_type" IS 'Tipo de contenido: text, audio, audio_tts, buttons, list.';

COMMENT ON COLUMN "outgoing_messages"."content" IS 'Contenido principal del mensaje. Puede ser texto plano o representación base del contenido.';

COMMENT ON COLUMN "outgoing_messages"."status" IS 'Estado del envío: pending, processing, sending, sent, failed.';

COMMENT ON COLUMN "outgoing_messages"."attempt_count" IS 'Cantidad de intentos de envío realizados.';

COMMENT ON COLUMN "outgoing_messages"."locked_at" IS 'Momento en que un worker tomó este registro para despacharlo.';

COMMENT ON COLUMN "outgoing_messages"."sent_at" IS 'Momento en que el sistema marcó este mensaje como enviado.';

COMMENT ON COLUMN "outgoing_messages"."created_at" IS 'Fecha de creación del mensaje saliente.';

COMMENT ON COLUMN "outgoing_messages"."updated_at" IS 'Última actualización de esta fila.';

COMMENT ON COLUMN "outgoing_messages"."payload_json" IS 'Payload estructurado para el proveedor si el contenido requiere botones, listas u otros formatos.';

COMMENT ON COLUMN "outgoing_messages"."scheduled_at" IS 'Fecha/hora programada de envío. Permite colas diferidas.';

COMMENT ON COLUMN "outgoing_messages"."last_attempt_at" IS 'Fecha del último intento de despacho.';

COMMENT ON COLUMN "outgoing_messages"."error_detail" IS 'Detalle del último error de envío.';

COMMENT ON COLUMN "outgoing_messages"."provider_response" IS 'Respuesta cruda del proveedor de mensajería.';

COMMENT ON COLUMN "outgoing_messages"."provider_delivery_id" IS 'ID de entrega devuelto por el proveedor.';

COMMENT ON TABLE "memoria_chat" IS 'TABLA: memoria_chat

QUÉ ES:
Memoria de largo plazo resumida del usuario.

PARA QUÉ SIRVE:
- Recordar contexto entre conversaciones.
- Evitar recalcular siempre lo mismo.
- Mejorar continuidad sin depender del historial crudo completo.

QUÉ DEBE IR AQUÍ:
- Resúmenes.
- Preferencias del usuario.
- Temas clave persistentes.

QUÉ NO DEBE IR AQUÍ:
- Registros maestros clínicos.
- Mensajes crudos completos.
';

COMMENT ON COLUMN "memoria_chat"."id" IS 'Clave primaria interna del registro de memoria.';

COMMENT ON COLUMN "memoria_chat"."usuario_id" IS 'Usuario al que pertenece esta memoria resumida.';

COMMENT ON COLUMN "memoria_chat"."resumen" IS 'Resumen corto acumulado de lo más importante que se sabe del usuario o de la conversación.';

COMMENT ON COLUMN "memoria_chat"."temas_clave" IS 'Lista o resumen de temas importantes tratados con el usuario.';

COMMENT ON COLUMN "memoria_chat"."ultima_recomendacion" IS 'Última recomendación relevante entregada al usuario.';

COMMENT ON COLUMN "memoria_chat"."modo_respuesta_preferido" IS 'Preferencia aproximada del usuario: texto, audio o mixto.';

COMMENT ON COLUMN "memoria_chat"."ultima_interaccion" IS 'Última fecha en la que hubo interacción relevante.';

COMMENT ON COLUMN "memoria_chat"."actualizado_en" IS 'Última fecha en la que se actualizó esta memoria.';

COMMENT ON COLUMN "memoria_chat"."historial_mensajes" IS 'Historial resumido o comprimido de mensajes relevantes. No debería ser el log bruto completo.';

