COMMENT ON COLUMN "mae_departamento"."codigo_departamento" IS 'Código oficial corto del departamento, normalmente derivado del ubigeo.';

COMMENT ON COLUMN "mae_departamento"."nombre" IS 'Nombre oficial del departamento o región.';

COMMENT ON COLUMN "mae_departamento"."activo" IS 'Permite desactivar registros sin borrarlos físicamente.';

COMMENT ON TABLE "mae_provincia" IS 'TABLA: mae_provincia

QUÉ ES:
Maestro geográfico de provincias.

PARA QUÉ SIRVE:
- Ubicación estructurada.
- Dependencia jerárquica con departamento.
- Normalización para formularios, perfil y campañas.
';

