COMMENT ON COLUMN "mae_provincia"."departamento_id" IS 'Departamento al que pertenece la provincia.';

COMMENT ON COLUMN "mae_provincia"."activo" IS 'Permite mantener histórico o desactivar sin borrar.';

COMMENT ON TABLE "mae_distrito" IS 'TABLA: mae_distrito

