COMMENT ON COLUMN "mae_distrito"."superficie" IS 'Superficie territorial estimada del distrito.';

COMMENT ON COLUMN "mae_distrito"."latitud" IS 'Latitud referencial del distrito.';

COMMENT ON COLUMN "mae_distrito"."longitud" IS 'Longitud referencial del distrito.';

