COMMENT ON COLUMN "mae_dieta_terapeutica"."descripcion" IS 'Descripción funcional de cuándo y cómo se usa esta dieta.';

COMMENT ON COLUMN "mae_dieta_terapeutica"."activo" IS 'Marca si la dieta sigue disponible en el sistema.';

COMMENT ON TABLE "mae_textura_dieta" IS 'TABLA: mae_textura_dieta

