COMMENT ON COLUMN "mae_textura_dieta"."descripcion" IS 'Descripción de la consistencia y su uso clínico o funcional.';

COMMENT ON COLUMN "mae_textura_dieta"."activo" IS 'Marca si esta textura está vigente o disponible.';

