COMMENT ON TABLE "mae_alias_semantico" IS 'TABLA: mae_alias_semantico

QUÉ ES:
Catálogo de sinónimos, frases naturales, errores comunes y variantes semánticas.

PARA QUÉ SIRVE:
- Resolver lenguaje del usuario sin llamar siempre a IA.
- Mapear expresiones coloquiales a entidades canónicas.
- Mejorar exact match, fuzzy match y búsqueda vectorial.

EJEMPLOS:
- "azúcar alta" -> enfermedad o grupo DIABETES
- "presión alta" -> grupo HIPERTENSION
- "no tolero leche" -> restricción SIN_LACTOSA
';

COMMENT ON COLUMN "mae_alias_semantico"."id" IS 'Clave primaria interna del alias semántico.';

COMMENT ON COLUMN "mae_alias_semantico"."entidad_tipo" IS 'Tipo de entidad canónica a la que apunta el alias. Ejemplo: ENFERMEDAD_CIE10 o RESTRICCION_ALIMENTARIA.';

COMMENT ON COLUMN "mae_alias_semantico"."entidad_codigo" IS 'Código canónico de la entidad dentro de su maestro.';

COMMENT ON COLUMN "mae_alias_semantico"."alias_texto" IS 'Alias visible, sin normalizar. Ejemplo: azúcar alta, presión alta, no tolero leche.';

COMMENT ON COLUMN "mae_alias_semantico"."alias_normalizado" IS 'Versión normalizada del alias para búsquedas exactas o fuzzy.';

COMMENT ON COLUMN "mae_alias_semantico"."idioma" IS 'Idioma del alias, útil si luego agregas variantes en otros idiomas.';

COMMENT ON COLUMN "mae_alias_semantico"."es_canonico" IS 'Marca si este alias corresponde al nombre oficial o solo a una variante útil.';

COMMENT ON COLUMN "mae_alias_semantico"."prioridad" IS 'Prioridad del alias cuando existan varias formas de mapear el mismo concepto.';

COMMENT ON COLUMN "mae_alias_semantico"."activo" IS 'Permite activar o desactivar el alias sin borrarlo.';

COMMENT ON COLUMN "mae_alias_semantico"."creado_en" IS 'Fecha de creación del alias.';

COMMENT ON COLUMN "mae_alias_semantico"."actualizado_en" IS 'Última actualización del alias.';

COMMENT ON TABLE "semantic_catalog" IS 'TABLA: semantic_catalog

QUÉ ES:
Índice semántico unificado y searchable del sistema.

PARA QUÉ SIRVE:
- Concentrar texto indexable para búsquedas exactas, fuzzy y vectoriales.
- Evitar consultar múltiples tablas de catálogo por separado.
- Servir como base para una capa híbrida de resolución.

IMPORTANTE:
Esta tabla no reemplaza los maestros.
Solo ayuda a encontrarlos rápido y barato.
';

COMMENT ON COLUMN "semantic_catalog"."id" IS 'Clave primaria interna del catálogo semántico indexable.';

COMMENT ON COLUMN "semantic_catalog"."entidad_tipo" IS 'Tipo canónico de entidad que representa esta entrada.';

COMMENT ON COLUMN "semantic_catalog"."entidad_codigo" IS 'Código canónico de la entidad representada.';

COMMENT ON COLUMN "semantic_catalog"."alias_semantico_id" IS 'Alias que originó esta entrada, si provino de mae_alias_semantico.';

COMMENT ON COLUMN "semantic_catalog"."nombre_canonico" IS 'Nombre oficial o canónico de la entidad.';

COMMENT ON COLUMN "semantic_catalog"."texto_busqueda" IS 'Texto principal que se quiere buscar o comparar.';

COMMENT ON COLUMN "semantic_catalog"."texto_normalizado" IS 'Versión normalizada del texto de búsqueda.';

COMMENT ON COLUMN "semantic_catalog"."peso_lexico" IS 'Peso relativo para estrategias léxicas o trigram.';

COMMENT ON COLUMN "semantic_catalog"."peso_semantico" IS 'Peso relativo para estrategias vectoriales o semánticas.';

COMMENT ON COLUMN "semantic_catalog"."embedding" IS 'Representación vectorial del texto. En PostgreSQL real sería vector(1536) u otra dimensión.';

COMMENT ON COLUMN "semantic_catalog"."embedding_model" IS 'Nombre del modelo usado para generar el embedding.';

COMMENT ON COLUMN "semantic_catalog"."activo" IS 'Marca si la entrada sigue activa en el índice semántico.';

COMMENT ON COLUMN "semantic_catalog"."generado_en" IS 'Fecha de generación de esta entrada semántica.';

COMMENT ON COLUMN "semantic_catalog"."actualizado_en" IS 'Última actualización de esta entrada.';

COMMENT ON TABLE "semantic_resolution_cache" IS 'TABLA: semantic_resolution_cache

QUÉ ES:
Cache de resoluciones semánticas reutilizables.

PARA QUÉ SIRVE:
- Evitar recalcular fuzzy, vector o IA para la misma consulta.
- Reducir latencia.
- Bajar costo de llamadas al modelo.

IMPORTANTE:
Esta tabla es clave en la estrategia de ahorro de IA.
';

COMMENT ON COLUMN "semantic_resolution_cache"."id" IS 'Clave primaria interna del cache de resolución semántica.';

COMMENT ON COLUMN "semantic_resolution_cache"."scope" IS 'Contexto en el que se hizo la resolución. Ejemplo: PROFILE_FIELD, ENTITY_MATCH, NUTRITION_CLASSIFICATION.';

COMMENT ON COLUMN "semantic_resolution_cache"."field_code" IS 'Campo concreto que se quería resolver. Ejemplo: enfermedad, objetivo, restriccion.';

COMMENT ON COLUMN "semantic_resolution_cache"."query_texto" IS 'Texto original consultado.';

COMMENT ON COLUMN "semantic_resolution_cache"."query_normalizada" IS 'Versión normalizada de la consulta para reutilización de resultados.';

COMMENT ON COLUMN "semantic_resolution_cache"."entidad_tipo_resuelta" IS 'Tipo final de entidad resuelta.';

COMMENT ON COLUMN "semantic_resolution_cache"."entidad_codigo_resuelto" IS 'Código final resuelto dentro del maestro correspondiente.';

COMMENT ON COLUMN "semantic_resolution_cache"."estrategia_usada" IS 'Método usado para resolver: EXACT, TRGM, VECTOR, HYBRID, LLM.';

COMMENT ON COLUMN "semantic_resolution_cache"."confidence" IS 'Confianza final con la que se guardó el resultado en cache.';

COMMENT ON COLUMN "semantic_resolution_cache"."compatible_con_reglas" IS 'Indica si la resolución fue coherente con reglas relacionales o de negocio.';

COMMENT ON COLUMN "semantic_resolution_cache"."top_candidates_json" IS 'Lista opcional de candidatos considerados durante la resolución.';

COMMENT ON COLUMN "semantic_resolution_cache"."hit_count" IS 'Número de veces que esta resolución en cache ha sido reutilizada.';

COMMENT ON COLUMN "semantic_resolution_cache"."expires_at" IS 'Fecha de expiración de la entrada de cache, si aplica.';

COMMENT ON COLUMN "semantic_resolution_cache"."creado_en" IS 'Fecha de creación de la entrada en cache.';

COMMENT ON COLUMN "semantic_resolution_cache"."actualizado_en" IS 'Última actualización del cache.';

COMMENT ON TABLE "semantic_match_log" IS 'TABLA: semantic_match_log

QUÉ ES:
Log detallado de intentos de resolución semántica.

PARA QUÉ SIRVE:
- Auditar qué estrategia funcionó.
- Afinar thresholds.
- Medir ahorro de IA.
- Detectar puntos débiles del sistema.

IMPORTANTE:
Es una tabla de observabilidad, no de negocio.
';

COMMENT ON COLUMN "semantic_match_log"."id" IS 'Clave primaria interna del log de matching semántico.';

COMMENT ON COLUMN "semantic_match_log"."usuario_id" IS 'Usuario que originó la consulta o el texto que se quiso resolver.';

COMMENT ON COLUMN "semantic_match_log"."incoming_message_id" IS 'Mensaje entrante asociado al intento de matching, si existe.';

COMMENT ON COLUMN "semantic_match_log"."scope" IS 'Contexto de resolución.';

COMMENT ON COLUMN "semantic_match_log"."field_code" IS 'Campo que se intentó resolver.';

COMMENT ON COLUMN "semantic_match_log"."query_texto" IS 'Texto original evaluado.';

COMMENT ON COLUMN "semantic_match_log"."query_normalizada" IS 'Texto normalizado usado en el pipeline.';

COMMENT ON COLUMN "semantic_match_log"."estrategia_usada" IS 'Método usado para resolver el matching.';

COMMENT ON COLUMN "semantic_match_log"."exact_match" IS 'Marca si hubo match exacto sin necesidad de fuzzy o vector.';

COMMENT ON COLUMN "semantic_match_log"."trigram_score" IS 'Puntaje de similitud léxica o trigram, si aplica.';

COMMENT ON COLUMN "semantic_match_log"."vector_score" IS 'Puntaje de similitud semántica/vectorial, si aplica.';

COMMENT ON COLUMN "semantic_match_log"."confidence_final" IS 'Confianza final del matching.';

COMMENT ON COLUMN "semantic_match_log"."entidad_tipo_resuelta" IS 'Tipo de entidad resuelta finalmente.';

COMMENT ON COLUMN "semantic_match_log"."entidad_codigo_resuelto" IS 'Código de la entidad resuelta finalmente.';

COMMENT ON COLUMN "semantic_match_log"."escalado_a_ia" IS 'Marca si el caso terminó escalando a IA.';

COMMENT ON COLUMN "semantic_match_log"."decidido_por_regla" IS 'Marca si la decisión final vino de reglas relacionales y no solo de similitud.';

COMMENT ON COLUMN "semantic_match_log"."latency_ms" IS 'Tiempo aproximado de resolución en milisegundos.';

COMMENT ON COLUMN "semantic_match_log"."error_detail" IS 'Error o detalle si el matching falló.';

COMMENT ON COLUMN "semantic_match_log"."creado_en" IS 'Momento en que ocurrió este intento de matching.';

COMMENT ON TABLE "semantic_review_queue" IS 'TABLA: semantic_review_queue

QUÉ ES:
Cola de revisión para casos ambiguos.

PARA QUÉ SIRVE:
- Evitar mandar automáticamente todo a IA.
- Mantener casos dudosos para revisión posterior.
- Mejorar reglas y alias con aprendizaje operativo.
';

COMMENT ON COLUMN "semantic_review_queue"."id" IS 'Clave primaria interna del caso enviado a revisión.';

COMMENT ON COLUMN "semantic_review_queue"."usuario_id" IS 'Usuario relacionado con el caso ambiguo.';

COMMENT ON COLUMN "semantic_review_queue"."incoming_message_id" IS 'Mensaje que originó el caso ambiguo, si aplica.';

COMMENT ON COLUMN "semantic_review_queue"."scope" IS 'Contexto del caso.';

COMMENT ON COLUMN "semantic_review_queue"."field_code" IS 'Campo que no pudo resolverse con suficiente claridad.';

COMMENT ON COLUMN "semantic_review_queue"."query_texto" IS 'Texto original problemático o ambiguo.';

COMMENT ON COLUMN "semantic_review_queue"."query_normalizada" IS 'Versión normalizada del texto.';

COMMENT ON COLUMN "semantic_review_queue"."top_candidates_json" IS 'Candidatos sugeridos por el pipeline antes de revisión.';

COMMENT ON COLUMN "semantic_review_queue"."razon" IS 'Razón por la cual se envió a revisión: LOW_CONFIDENCE, CONFLICT, NO_MATCH, RULE_MISMATCH.';

COMMENT ON COLUMN "semantic_review_queue"."estado" IS 'Estado de la revisión: PENDING, REVIEWED, DISMISSED, RESOLVED.';

COMMENT ON COLUMN "semantic_review_queue"."resolucion_manual_tipo" IS 'Tipo de entidad elegido manualmente si hubo resolución humana.';

COMMENT ON COLUMN "semantic_review_queue"."resolucion_manual_codigo" IS 'Código elegido manualmente si hubo resolución humana.';

COMMENT ON COLUMN "semantic_review_queue"."observacion" IS 'Comentarios del revisor o del sistema sobre el caso.';

COMMENT ON COLUMN "semantic_review_queue"."creado_en" IS 'Fecha de creación del caso.';

COMMENT ON COLUMN "semantic_review_queue"."resuelto_en" IS 'Fecha de cierre o resolución del caso.';

COMMENT ON TABLE "embedding_jobs" IS 'TABLA: embedding_jobs

QUÉ ES:
Cola de trabajos para generación o regeneración de embeddings.

PARA QUÉ SIRVE:
- Desacoplar el costo de embedding del flujo principal.
- Permitir recalcular embeddings cuando cambie el modelo.
- Soportar procesos batch o diferidos.
';

COMMENT ON COLUMN "embedding_jobs"."id" IS 'Clave primaria interna del job de embedding.';

COMMENT ON COLUMN "embedding_jobs"."source_table" IS 'Tabla fuente de la que viene el texto a embeber.';

COMMENT ON COLUMN "embedding_jobs"."source_id" IS 'ID de la fila fuente dentro de la tabla indicada.';

COMMENT ON COLUMN "embedding_jobs"."texto_fuente" IS 'Texto que debe convertirse en embedding.';

COMMENT ON COLUMN "embedding_jobs"."modelo" IS 'Modelo de embeddings que debe usarse.';

COMMENT ON COLUMN "embedding_jobs"."estado" IS 'Estado del job: PENDING, PROCESSING, DONE, FAILED.';

COMMENT ON COLUMN "embedding_jobs"."retry_count" IS 'Número de reintentos del job.';

COMMENT ON COLUMN "embedding_jobs"."error_detail" IS 'Detalle del último error si el embedding falló.';

COMMENT ON COLUMN "embedding_jobs"."creado_en" IS 'Fecha de creación del job.';

COMMENT ON COLUMN "embedding_jobs"."actualizado_en" IS 'Última actualización del job.';

COMMENT ON COLUMN "embedding_jobs"."procesado_en" IS 'Fecha en la que el job terminó correctamente, si aplica.';

COMMENT ON TABLE "formularios" IS 'TABLA: formularios

QUÉ ES:
Catálogo de formularios del sistema.

PARA QUÉ SIRVE:
- Versionar encuestas o formularios.
- Controlar disponibilidad temporal.
- Mantener histórico si cambia el contenido.
';

COMMENT ON COLUMN "formularios"."id" IS 'Clave primaria interna del formulario.';

COMMENT ON COLUMN "formularios"."codigo" IS 'Código funcional del formulario. Debe ser estable a lo largo del tiempo.';

COMMENT ON COLUMN "formularios"."nombre" IS 'Nombre visible o descriptivo del formulario.';

COMMENT ON COLUMN "formularios"."version" IS 'Versión del formulario, útil para cambios de estructura sin romper histórico.';

COMMENT ON COLUMN "formularios"."activo" IS 'Marca si el formulario está disponible para uso.';

COMMENT ON COLUMN "formularios"."fecha_inicio" IS 'Fecha desde la que el formulario está disponible.';

COMMENT ON COLUMN "formularios"."fecha_cierre" IS 'Fecha de cierre del formulario si deja de estar vigente.';

COMMENT ON COLUMN "formularios"."creado_en" IS 'Fecha de creación del formulario.';

COMMENT ON TABLE "formulario_en_progreso" IS 'TABLA: formulario_en_progreso

QUÉ ES:
Estado parcial de un formulario que todavía no termina.

PARA QUÉ SIRVE:
- Retomar un flujo sin perder respuestas.
- Llevar control de progreso.
- Soportar formularios conversacionales multi-turno.
';

COMMENT ON COLUMN "formulario_en_progreso"."id" IS 'Clave primaria interna del avance parcial del formulario.';

COMMENT ON COLUMN "formulario_en_progreso"."formulario_id" IS 'Formulario que el usuario está respondiendo.';

COMMENT ON COLUMN "formulario_en_progreso"."usuario_id" IS 'Usuario con un flujo actualmente en progreso para ese formulario/encuesta.';

COMMENT ON COLUMN "formulario_en_progreso"."estado_actual" IS 'Paso actual o estado del formulario en progreso.';

COMMENT ON COLUMN "formulario_en_progreso"."respuestas_parciales" IS 'Respuestas aún no consolidadas del formulario.';

COMMENT ON COLUMN "formulario_en_progreso"."uso_audio" IS 'Marca si el usuario utilizó audio durante esta interacción de formulario.';

COMMENT ON COLUMN "formulario_en_progreso"."uso_imagen" IS 'Marca si el usuario utilizó imagen durante esta interacción.';

COMMENT ON COLUMN "formulario_en_progreso"."iniciado_en" IS 'Fecha de inicio del formulario en progreso.';

COMMENT ON COLUMN "formulario_en_progreso"."actualizado_en" IS 'Última actualización del avance parcial.';

COMMENT ON COLUMN "formulario_en_progreso"."completado_en" IS 'Fecha de finalización si el formulario ya fue completado.';

COMMENT ON COLUMN "formulario_en_progreso"."audio_test_requested" IS 'Marca si se pidió probar audio.';

COMMENT ON COLUMN "formulario_en_progreso"."audio_test_completed" IS 'Marca si la prueba de audio se completó.';

COMMENT ON COLUMN "formulario_en_progreso"."audio_test_declined" IS 'Marca si el usuario rechazó la prueba de audio.';

COMMENT ON COLUMN "formulario_en_progreso"."image_test_requested" IS 'Marca si se pidió probar imagen.';

COMMENT ON COLUMN "formulario_en_progreso"."image_test_completed" IS 'Marca si la prueba de imagen se completó.';

COMMENT ON COLUMN "formulario_en_progreso"."image_test_declined" IS 'Marca si el usuario rechazó la prueba de imagen.';

COMMENT ON TABLE "respuestas_formulario" IS 'TABLA: respuestas_formulario

QUÉ ES:
Respuesta final consolidada de un formulario.

