COMMENT ON COLUMN "respuestas_formulario"."audio_no_aplica" IS 'Marca si audio no aplicaba a esta evaluación.';

COMMENT ON COLUMN "respuestas_formulario"."imagen_evaluada" IS 'Marca si el componente de imagen fue evaluado.';

COMMENT ON COLUMN "respuestas_formulario"."imagen_no_aplica" IS 'Marca si imagen no aplicaba a esta evaluación.';

COMMENT ON COLUMN "respuestas_formulario"."correo_proporcionado" IS 'Marca rápida de si el usuario sí dejó correo.';

COMMENT ON TABLE "evaluacion_usabilidad" IS 'TABLA: evaluacion_usabilidad

