COMMENT ON COLUMN "documentos_rag"."estado" IS 'Estado del documento dentro del pipeline RAG: activo, procesando, error, archivado.';

COMMENT ON COLUMN "documentos_rag"."creado_en" IS 'Fecha de creación del documento en el sistema.';

COMMENT ON COLUMN "documentos_rag"."actualizado_en" IS 'Última actualización del documento.';

COMMENT ON TABLE "fragmentos_rag" IS 'TABLA: fragmentos_rag

QUÉ ES:
Fragmentos indexables de los documentos fuente.

PARA QUÉ SIRVE:
- Soportar búsqueda semántica o recuperación por chunks.
- Mantener trazabilidad hacia el documento original.
';

COMMENT ON COLUMN "fragmentos_rag"."id" IS 'Clave primaria interna del fragmento o chunk.';

COMMENT ON COLUMN "fragmentos_rag"."documento_id" IS 'Documento del que salió este fragmento.';

