COMMENT ON COLUMN "fragmentos_rag"."numero_fragmento" IS 'Orden secuencial del fragmento dentro del documento.';

COMMENT ON COLUMN "fragmentos_rag"."contenido" IS 'Texto del fragmento usado para recuperación.';

COMMENT ON COLUMN "fragmentos_rag"."metadata" IS 'Metadatos opcionales del fragmento.';

COMMENT ON COLUMN "fragmentos_rag"."embedding" IS 'Representación vectorial del fragmento. En PostgreSQL real sería vector(1536).';

COMMENT ON COLUMN "fragmentos_rag"."creado_en" IS 'Fecha de creación del fragmento.';

